1	// endian.h — big-endian read/write helpers, byte-wise only.
2	//
3	// Wire formats (ITCH and our own record codec) are big-endian; the dev and
4	// target machines are both little-endian x86-64. These helpers NEVER use
5	// pointer casts or memcpy-of-struct — always explicit shifts/masks — so
6	// they are correct at unaligned offsets and free of strict-aliasing UB.
7	#ifndef JNX_ENDIAN_H
8	#define JNX_ENDIAN_H
9	
10	#include <cstdint>
11	
12	namespace jnx {
13	
14	inline uint16_t be_get_u16(const unsigned char* p) {
15	    return static_cast<uint16_t>(
16	        (static_cast<uint16_t>(p[0]) << 8) |
17	        (static_cast<uint16_t>(p[1])));
18	}
19	
20	inline uint32_t be_get_u32(const unsigned char* p) {
21	    return (static_cast<uint32_t>(p[0]) << 24) |
22	           (static_cast<uint32_t>(p[1]) << 16) |
23	           (static_cast<uint32_t>(p[2]) << 8) |
24	           (static_cast<uint32_t>(p[3]));
25	}
26	
27	inline uint64_t be_get_u64(const unsigned char* p) {
28	    return (static_cast<uint64_t>(p[0]) << 56) |
29	           (static_cast<uint64_t>(p[1]) << 48) |
30	           (static_cast<uint64_t>(p[2]) << 40) |
31	           (static_cast<uint64_t>(p[3]) << 32) |
32	           (static_cast<uint64_t>(p[4]) << 24) |
33	           (static_cast<uint64_t>(p[5]) << 16) |
34	           (static_cast<uint64_t>(p[6]) << 8) |
35	           (static_cast<uint64_t>(p[7]));
36	}
37	
38	inline void be_put_u16(unsigned char* p, uint16_t v) {
39	    p[0] = static_cast<unsigned char>((v >> 8) & 0xFF);
40	    p[1] = static_cast<unsigned char>(v & 0xFF);
41	}
42	
43	inline void be_put_u32(unsigned char* p, uint32_t v) {
44	    p[0] = static_cast<unsigned char>((v >> 24) & 0xFF);
45	    p[1] = static_cast<unsigned char>((v >> 16) & 0xFF);
46	    p[2] = static_cast<unsigned char>((v >> 8) & 0xFF);
47	    p[3] = static_cast<unsigned char>(v & 0xFF);
48	}
49	
50	inline void be_put_u64(unsigned char* p, uint64_t v) {
51	    p[0] = static_cast<unsigned char>((v >> 56) & 0xFF);
52	    p[1] = static_cast<unsigned char>((v >> 48) & 0xFF);
53	    p[2] = static_cast<unsigned char>((v >> 40) & 0xFF);
54	    p[3] = static_cast<unsigned char>((v >> 32) & 0xFF);
55	    p[4] = static_cast<unsigned char>((v >> 24) & 0xFF);
56	    p[5] = static_cast<unsigned char>((v >> 16) & 0xFF);
57	    p[6] = static_cast<unsigned char>((v >> 8) & 0xFF);
58	    p[7] = static_cast<unsigned char>(v & 0xFF);
59	}
60	
61	} // namespace jnx
62	
63	#endif // JNX_ENDIAN_H
64

1	// soup.h — SoupBinTCP packet codec + incremental stream framer.
2	//
3	// Wire format (JNX_PLAN.md §3.4): logical packet =
4	//   length:2:num (big-endian, EXCLUDES the length field itself)
5	//   + type:1:char + payload.
6	//
7	// Packet types:
8	//   server->client: 'A' LoginAccepted, 'J' LoginRejected, 'S' SequencedData,
9	//                   'H' server heartbeat, 'Z' EndOfSession, '+' Debug
10	//   client->server: 'L' LoginRequest, 'U' UnsequencedData,
11	//                   'R' client heartbeat, 'O' LogoutRequest
12	//
13	// Padding rules (pinned by the golden vectors):
14	//   LoginRequest:  username(6)/password(10) RIGHT-padded with spaces;
15	//                  requested_session(10) and requested_sequence(20, ASCII
16	//                  digits) LEFT-padded with spaces.
17	//   LoginAccepted: session(10) and sequence(20, ASCII digits) LEFT-padded
18	//                  with spaces.
19	#ifndef JNX_SOUP_H
20	#define JNX_SOUP_H
21	
22	#include <cstddef>
23	#include <cstdint>
24	#include <vector>
25	
26	namespace jnx {
27	
28	// One framed logical packet. `payload` is the bytes after the type char
29	// (owned copy — valid independent of the framer; simplicity first).
30	struct SoupPacket {
31	    char type;
32	    std::vector<unsigned char> payload;
33	
34	    SoupPacket() : type('\0') {}
35	};
36	
37	// --- typed payload structs (fields host-order / stripped strings) -------
38	
39	struct SoupLoginRequest {
40	    char username[7];           // <= 6 chars
41	    char password[11];          // <= 10 chars
42	    char requested_session[11]; // <= 10 chars ("" = current session)
43	    uint64_t requested_sequence;
44	
45	    SoupLoginRequest() : requested_sequence(0) {
46	        username[0] = '\0';
47	        password[0] = '\0';
48	        requested_session[0] = '\0';
49	    }
50	};
51	
52	struct SoupLoginAccepted {
53	    char session[11]; // <= 10 chars
54	    uint64_t sequence;
55	
56	    SoupLoginAccepted() : sequence(0) { session[0] = '\0'; }
57	};
58	
59	struct SoupLoginRejected {
60	    char reject_code; // 'A' not authorized, 'S' session unavailable
61	
62	    SoupLoginRejected() : reject_code('\0') {}
63	};
64	
65	// --- payload parsers (from SoupPacket.payload) ---------------------------
66	// Return false + static *err on wrong payload length / non-numeric seq.
67	
68	bool soup_parse_login_request(const unsigned char* payload, size_t len,
69	                              SoupLoginRequest& out, const char** err);
70	bool soup_parse_login_accepted(const unsigned char* payload, size_t len,
71	                               SoupLoginAccepted& out, const char** err);
72	bool soup_parse_login_rejected(const unsigned char* payload, size_t len,
73	                               SoupLoginRejected& out, const char** err);
74	
75	// --- packet builders ------------------------------------------------------
76	// Each writes a COMPLETE wire packet (2-byte length prefix + type +
77	// payload) into buf and returns total bytes written. Callers size buf via
78	// the constants below (payload-carrying builders need 3 + payload_len).
79	
80	const size_t SOUP_LOGIN_REQUEST_WIRE = 2 + 1 + 6 + 10 + 10 + 20; // 49
81	const size_t SOUP_LOGIN_ACCEPTED_WIRE = 2 + 1 + 10 + 20;         // 33
82	const size_t SOUP_LOGIN_REJECTED_WIRE = 2 + 1 + 1;               // 4
83	const size_t SOUP_BARE_WIRE = 2 + 1; // heartbeats / logout / end-of-session
84	
85	size_t soup_build_login_request(const SoupLoginRequest& in,
86	                                unsigned char* buf);
87	size_t soup_build_login_accepted(const SoupLoginAccepted& in,
88	                                 unsigned char* buf);
89	size_t soup_build_login_rejected(const SoupLoginRejected& in,
90	                                 unsigned char* buf);
91	// Generic builder for payload-carrying ('S','U','+') and bare
92	// ('H','Z','R','O') packets. payload may be NULL when payload_len == 0.
93	size_t soup_build_packet(char type, const unsigned char* payload,
94	                         size_t payload_len, unsigned char* buf);
95	
96	// --- stream framer --------------------------------------------------------
97	// Incremental: tolerates byte-at-a-time input and a length prefix split
98	// across feed() calls. Packets are returned in order via next(), which
99	// copies the payload into the caller's SoupPacket (the returned packet
100	// stays valid after further feed()/next() calls).
101	class SoupFramer {
102	public:
103	    SoupFramer() : bad_frames_(0) {}
104	
105	    void feed(const unsigned char* data, size_t len);
106	
107	    // Extracts the next complete packet; returns false if none buffered.
108	    bool next(SoupPacket& out);
109	
110	    // Count of malformed frames skipped (declared length 0 — a packet must
111	    // contain at least the type char).
112	    uint64_t bad_frames() const { return bad_frames_; }
113	
114	private:
115	    std::vector<unsigned char> buf_;
116	    uint64_t bad_frames_;
117	};
118	
119	} // namespace jnx
120	
121	#endif // JNX_SOUP_H
122

1	// jsonvec.h — minimal JSON reader for EXACTLY the golden-vector file shape:
2	//
3	//   {"vectors": [{"name": "...", "type": "...", "hex": "...",
4	//                 "fields": {"k": <int-or-string>, ...}}, ...]}
5	//
6	// String values may contain only plain characters (no escapes are used in
7	// the vector files; an escape fails loudly). Integers are non-negative and
8	// fit uint64. Anything unexpected -> loud failure (message + false).
9	// NOT a general JSON parser and never will be. Test-only helper.
10	#ifndef JNX_JSONVEC_H
11	#define JNX_JSONVEC_H
12	
13	#include <cstdint>
14	#include <cstdio>
15	#include <fstream>
16	#include <map>
17	#include <sstream>
18	#include <string>
19	#include <vector>
20	
21	namespace jsonvec {
22	
23	struct Vector {
24	    std::string name;
25	    std::string type;
26	    std::string hex;
27	    std::map<std::string, std::string> str_fields;
28	    std::map<std::string, uint64_t> int_fields;
29	
30	    bool has_int(const std::string& k) const {
31	        return int_fields.find(k) != int_fields.end();
32	    }
33	    bool has_str(const std::string& k) const {
34	        return str_fields.find(k) != str_fields.end();
35	    }
36	};
37	
38	class Parser {
39	public:
40	    Parser(const std::string& text) : s_(text), pos_(0) {}
41	
42	    bool fail(const char* why) {
43	        std::fprintf(stderr, "jsonvec: parse error at offset %zu: %s\n", pos_,
44	                     why);
45	        return false;
46	    }
47	
48	    void skip_ws() {
49	        while (pos_ < s_.size() &&
50	               (s_[pos_] == ' ' || s_[pos_] == '\t' || s_[pos_] == '\n' ||
51	                s_[pos_] == '\r')) {
52	            ++pos_;
53	        }
54	    }
55	
56	    bool expect(char c) {
57	        skip_ws();
58	        if (pos_ >= s_.size() || s_[pos_] != c) {
59	            std::fprintf(stderr,
60	                         "jsonvec: parse error at offset %zu: expected '%c'\n",
61	                         pos_, c);
62	            return false;
63	        }
64	        ++pos_;
65	        return true;
66	    }
67	
68	    bool peek(char c) {
69	        skip_ws();
70	        return pos_ < s_.size() && s_[pos_] == c;
71	    }
72	
73	    bool parse_string(std::string& out) {
74	        if (!expect('"')) return false;
75	        out.clear();
76	        while (pos_ < s_.size() && s_[pos_] != '"') {
77	            if (s_[pos_] == '\\') {
78	                return fail("string escapes not supported");
79	            }
80	            out.push_back(s_[pos_]);
81	            ++pos_;
82	        }
83	        if (pos_ >= s_.size()) return fail("unterminated string");
84	        ++pos_; // closing quote
85	        return true;
86	    }
87	
88	    bool parse_uint(uint64_t& out) {
89	        skip_ws();
90	        if (pos_ >= s_.size() || s_[pos_] < '0' || s_[pos_] > '9') {
91	            return fail("expected non-negative integer");
92	        }
93	        out = 0;
94	        while (pos_ < s_.size() && s_[pos_] >= '0' && s_[pos_] <= '9') {
95	            out = out * 10 + static_cast<uint64_t>(s_[pos_] - '0');
96	            ++pos_;
97	        }
98	        return true;
99	    }
100	
101	    // Parses the "fields" object: string or uint values only.
102	    bool parse_fields(Vector& v) {
103	        if (!expect('{')) return false;
104	        if (peek('}')) {
105	            ++pos_;
106	            return true;
107	        }
108	        for (;;) {
109	            std::string key;
110	            skip_ws();
111	            if (!parse_string(key)) return false;
112	            if (!expect(':')) return false;
113	            skip_ws();
114	            if (peek('"')) {
115	                std::string sval;
116	                if (!parse_string(sval)) return false;
117	                v.str_fields[key] = sval;
118	            } else {
119	                uint64_t ival = 0;
120	                if (!parse_uint(ival)) return false;
121	                v.int_fields[key] = ival;
122	            }
123	            skip_ws();
124	            if (peek(',')) {
125	                ++pos_;
126	                continue;
127	            }
128	            return expect('}');
129	        }
130	    }
131	
132	    bool parse_vector(Vector& v) {
133	        if (!expect('{')) return false;
134	        for (;;) {
135	            std::string key;
136	            skip_ws();
137	            if (!parse_string(key)) return false;
138	            if (!expect(':')) return false;
139	            skip_ws();
140	            if (key == "name") {
141	                if (!parse_string(v.name)) return false;
142	            } else if (key == "type") {
143	                if (!parse_string(v.type)) return false;
144	            } else if (key == "hex") {
145	                if (!parse_string(v.hex)) return false;
146	            } else if (key == "fields") {
147	                if (!parse_fields(v)) return false;
148	            } else {
149	                return fail("unexpected key in vector object");
150	            }
151	            skip_ws();
152	            if (peek(',')) {
153	                ++pos_;
154	                continue;
155	            }
156	            return expect('}');
157	        }
158	    }
159	
160	    bool parse_file(std::vector<Vector>& out) {
161	        if (!expect('{')) return false;
162	        std::string key;
163	        if (!parse_string(key)) return false;
164	        if (key != "vectors") return fail("expected top-level key 'vectors'");
165	        if (!expect(':')) return false;
166	        if (!expect('[')) return false;
167	        if (peek(']')) {
168	            ++pos_;
169	        } else {
170	            for (;;) {
171	                Vector v;
172	                if (!parse_vector(v)) return false;
173	                out.push_back(v);
174	                skip_ws();
175	                if (peek(',')) {
176	                    ++pos_;
177	                    continue;
178	                }
179	                if (!expect(']')) return false;
180	                break;
181	            }
182	        }
183	        if (!expect('}')) return false;
184	        skip_ws();
185	        if (pos_ != s_.size()) return fail("trailing garbage after document");
186	        return true;
187	    }
188	
189	private:
190	    const std::string& s_;
191	    size_t pos_;
192	};
193	
194	// Loads a vector file; returns false (after printing why) on any problem.
195	inline bool load(const std::string& path, std::vector<Vector>& out) {
196	    std::ifstream in(path.c_str());
197	    if (!in.is_open()) {
198	        std::fprintf(stderr, "jsonvec: cannot open %s\n", path.c_str());
199	        return false;
200	    }
201	    std::ostringstream ss;
202	    ss << in.rdbuf();
203	    std::string text = ss.str();
204	    Parser p(text);
205	    return p.parse_file(out);
206	}
207	
208	// Hex string -> bytes. Returns false on odd length / non-hex chars.
209	inline bool hex_to_bytes(const std::string& hex,
210	                         std::vector<unsigned char>& out) {
211	    if (hex.size() % 2 != 0) {
212	        std::fprintf(stderr, "jsonvec: odd-length hex string\n");
213	        return false;
214	    }
215	    out.clear();
216	    out.reserve(hex.size() / 2);
217	    for (size_t i = 0; i < hex.size(); i += 2) {
218	        unsigned v = 0;
219	        for (size_t j = 0; j < 2; ++j) {
220	            char c = hex[i + j];
221	            v <<= 4;
222	            if (c >= '0' && c <= '9') {
223	                v |= static_cast<unsigned>(c - '0');
224	            } else if (c >= 'a' && c <= 'f') {
225	                v |= static_cast<unsigned>(c - 'a' + 10);
226	            } else if (c >= 'A' && c <= 'F') {
227	                v |= static_cast<unsigned>(c - 'A' + 10);
228	            } else {
229	                std::fprintf(stderr, "jsonvec: bad hex char '%c'\n", c);
230	                return false;
231	            }
232	        }
233	        out.push_back(static_cast<unsigned char>(v));
234	    }
235	    return true;
236	}
237	
238	} // namespace jsonvec
239	
240	#endif // JNX_JSONVEC_H
241

1	// minitest.h — header-only C++11 micro test harness. No external deps.
2	//
3	// Usage: a test_*.cpp includes this header and writes:
4	//
5	//   #include "common/minitest.h"
6	//   TEST(some_name) {
7	//       CHECK(1 + 1 == 2);
8	//       CHECK_EQ(1 + 1, 2);
9	//   }
10	//
11	// The header supplies main(): it runs every registered test, prints one
12	// PASS/FAIL line per test plus a summary, and returns the number of
13	// failing tests as the process exit code (0 = all green).
14	#ifndef JNX_MINITEST_H
15	#define JNX_MINITEST_H
16	
17	#include <cstdio>
18	#include <sstream>
19	#include <string>
20	#include <vector>
21	
22	namespace minitest {
23	
24	struct TestCase {
25	    const char* name;
26	    void (*fn)(int& failures);
27	};
28	
29	// Function-local static registry: avoids static-init-order fiasco since
30	// the vector is constructed on first use (first REGISTRAR construction),
31	// not at an unspecified point relative to other globals.
32	inline std::vector<TestCase>& registry() {
33	    static std::vector<TestCase> tests;
34	    return tests;
35	}
36	
37	struct Registrar {
38	    Registrar(const char* name, void (*fn)(int& failures)) {
39	        TestCase tc;
40	        tc.name = name;
41	        tc.fn = fn;
42	        registry().push_back(tc);
43	    }
44	};
45	
46	// Streams two values via <sstream> so CHECK_EQ can print both operands
47	// on failure without requiring operator<< overload discovery tricks.
48	template <typename T>
49	inline std::string to_str(const T& v) {
50	    std::ostringstream oss;
51	    oss << v;
52	    return oss.str();
53	}
54	
55	} // namespace minitest
56	
57	#define TEST(name)                                                          \
58	    static void jnx_test_##name(int& jnx_failures);                         \
59	    static ::minitest::Registrar jnx_registrar_##name(#name, jnx_test_##name); \
60	    static void jnx_test_##name(int& jnx_failures)
61	
62	#define CHECK(expr)                                                         \
63	    do {                                                                    \
64	        if (!(expr)) {                                                      \
65	            std::fprintf(stderr, "  CHECK failed at %s:%d: %s\n", __FILE__, \
66	                         __LINE__, #expr);                                  \
67	            ++jnx_failures;                                                 \
68	        }                                                                   \
69	    } while (0)
70	
71	#define CHECK_EQ(a, b)                                                      \
72	    do {                                                                    \
73	        if (!((a) == (b))) {                                                \
74	            std::fprintf(stderr,                                           \
75	                         "  CHECK_EQ failed at %s:%d: %s == %s "            \
76	                         "(lhs=%s rhs=%s)\n",                                \
77	                         __FILE__, __LINE__, #a, #b,                        \
78	                         ::minitest::to_str(a).c_str(),                     \
79	                         ::minitest::to_str(b).c_str());                    \
80	            ++jnx_failures;                                                 \
81	        }                                                                   \
82	    } while (0)
83	
84	int main() {
85	    int total_failures = 0;
86	    int ntests = 0;
87	    for (std::vector<minitest::TestCase>::const_iterator it =
88	             minitest::registry().begin();
89	         it != minitest::registry().end(); ++it) {
90	        int failures = 0;
91	        it->fn(failures);
92	        ++ntests;
93	        if (failures == 0) {
94	            std::fprintf(stderr, "PASS %s\n", it->name);
95	        } else {
96	            std::fprintf(stderr, "FAIL %s (%d check(s) failed)\n", it->name,
97	                         failures);
98	        }
99	        total_failures += failures;
100	    }
101	    std::fprintf(stderr, "--- %d test(s), %d failure(s) ---\n", ntests,
102	                 total_failures);
103	    return total_failures;
104	}
105	
106	#endif // JNX_MINITEST_H
