1	// cfg.h — tiny header-only config: key=value file parser + `--key=value`
2	// argv overrides. No getopt, no external deps.
3	//
4	// File format: blank lines and lines starting with '#' (after leading
5	// whitespace) are ignored; otherwise `key=value`, whitespace around key and
6	// value is trimmed. Unknown keys are fine — this is just a string map, not
7	// a schema.
8	#ifndef JNX_CFG_H
9	#define JNX_CFG_H
10	
11	#include <cctype>
12	#include <cstdlib>
13	#include <fstream>
14	#include <sstream>
15	#include <string>
16	#include <unordered_map>
17	
18	namespace jnx {
19	
20	inline std::string cfg_trim(const std::string& s) {
21	    size_t start = 0;
22	    while (start < s.size() &&
23	           std::isspace(static_cast<unsigned char>(s[start]))) {
24	        ++start;
25	    }
26	    size_t end = s.size();
27	    while (end > start &&
28	           std::isspace(static_cast<unsigned char>(s[end - 1]))) {
29	        --end;
30	    }
31	    return s.substr(start, end - start);
32	}
33	
34	class Cfg {
35	public:
36	    // Parses a key=value file. Returns false if the file could not be
37	    // opened; a missing file is not fatal for callers that treat defaults
38	    // as sufficient. Malformed lines (no '=') are skipped.
39	    bool load_file(const std::string& path) {
40	        std::ifstream in(path.c_str());
41	        if (!in.is_open()) {
42	            return false;
43	        }
44	        std::string line;
45	        while (std::getline(in, line)) {
46	            std::string trimmed = cfg_trim(line);
47	            if (trimmed.empty() || trimmed[0] == '#') {
48	                continue;
49	            }
50	            size_t eq = trimmed.find('=');
51	            if (eq == std::string::npos) {
52	                continue;
53	            }
54	            std::string key = cfg_trim(trimmed.substr(0, eq));
55	            std::string value = cfg_trim(trimmed.substr(eq + 1));
56	            if (!key.empty()) {
57	                values_[key] = value;
58	            }
59	        }
60	        return true;
61	    }
62	
63	    // Applies `--key=value` overrides from argv (argv[0] is the program
64	    // name and is skipped). Args not matching `--key=value` are ignored.
65	    void apply_args(int argc, char** argv) {
66	        for (int i = 1; i < argc; ++i) {
67	            std::string arg(argv[i]);
68	            if (arg.size() < 3 || arg[0] != '-' || arg[1] != '-') {
69	                continue;
70	            }
71	            std::string rest = arg.substr(2);
72	            size_t eq = rest.find('=');
73	            if (eq == std::string::npos) {
74	                continue;
75	            }
76	            std::string key = rest.substr(0, eq);
77	            std::string value = rest.substr(eq + 1);
78	            if (!key.empty()) {
79	                values_[key] = value;
80	            }
81	        }
82	    }
83	
84	    std::string get(const std::string& key, const std::string& def) const {
85	        std::unordered_map<std::string, std::string>::const_iterator it =
86	            values_.find(key);
87	        if (it == values_.end()) {
88	            return def;
89	        }
90	        return it->second;
91	    }
92	
93	    long get_int(const std::string& key, long def) const {
94	        std::unordered_map<std::string, std::string>::const_iterator it =
95	            values_.find(key);
96	        if (it == values_.end() || it->second.empty()) {
97	            return def;
98	        }
99	        char* endptr = NULL;
100	        long v = std::strtol(it->second.c_str(), &endptr, 10);
101	        if (endptr == it->second.c_str()) {
102	            return def;
103	        }
104	        return v;
105	    }
106	
107	private:
108	    std::unordered_map<std::string, std::string> values_;
109	};
