27	
28	enum Level { LVL_DEBUG = 0, LVL_INFO = 1, LVL_WARN = 2, LVL_ERROR = 3 };
29	
30	inline const char* level_name(Level lvl) {
31	    switch (lvl) {
32	        case LVL_DEBUG: return "DEBUG";
33	        case LVL_INFO: return "INFO";
34	        case LVL_WARN: return "WARN";
35	        case LVL_ERROR: return "ERROR";
36	    }
37	    return "?";
38	}
39	
40	inline Level parse_level(const char* s) {
41	    if (s == NULL) return LVL_INFO;
42	    if (std::strcmp(s, "DEBUG") == 0) return LVL_DEBUG;
43	    if (std::strcmp(s, "INFO") == 0) return LVL_INFO;
44	    if (std::strcmp(s, "WARN") == 0) return LVL_WARN;
45	    if (std::strcmp(s, "ERROR") == 0) return LVL_ERROR;
46	    return LVL_INFO;
47	}
48	
