58	// Formats the current wall-clock time as YYYY-MM-DDTHH:MM:SS.mmm.
59	inline std::string timestamp_now() {
60	    uint64_t ns = ::jnx::now_ns();
61	    std::time_t secs = static_cast<std::time_t>(ns / 1000000000ULL);
62	    unsigned long ms = static_cast<unsigned long>((ns / 1000000ULL) % 1000ULL);
63	    std::tm tmv;
64	    ::gmtime_r(&secs, &tmv);
65	    char buf[64];
66	    std::snprintf(buf, sizeof(buf), "%04d-%02d-%02dT%02d:%02d:%02d.%03lu",
67	                  tmv.tm_year + 1900, tmv.tm_mon + 1, tmv.tm_mday,
68	                  tmv.tm_hour, tmv.tm_min, tmv.tm_sec, ms);
69	    return std::string(buf);
