11	inline uint64_t now_ns() {
12	    struct timespec ts;
13	    ::clock_gettime(CLOCK_REALTIME, &ts);
14	    return static_cast<uint64_t>(ts.tv_sec) * 1000000000ULL +
15	           static_cast<uint64_t>(ts.tv_nsec);
16	}
17	
18	// Monotonic time (not tied to wall clock, immune to NTP jumps), in
19	// nanoseconds. Use for measuring durations / timeouts.
20	inline uint64_t mono_ns() {
21	    struct timespec ts;
22	    ::clock_gettime(CLOCK_MONOTONIC, &ts);
23	    return static_cast<uint64_t>(ts.tv_sec) * 1000000000ULL +
24	           static_cast<uint64_t>(ts.tv_nsec);
25	}
